func Start(openAPISpec []byte, swaggerUIFS embed.FS, db *gorm.DB, configService configsvc.Service, readiness *appruntime.Readiness) {
	handler, err := buildHandler(openAPISpec, swaggerUIFS, db, configService, readiness)
	if err != nil {
		logger.Fatal("server", "http handler initialization failed", err, logger.Operation("buildHandler"))
	}

	// Allow BACKEND_PORT to be configured via environment, default to 8080
	port := os.Getenv("BACKEND_PORT")
	if port == "" {
		port = "8080"
	}

	address := ":" + port
	server := &http.Server{
		Addr:    address,
		Handler: handler,
	}

	serveErrs := make(chan error, 1)
	go func() {
		serveErrs <- server.ListenAndServe()
	}()

	logger.Info("server", "HTTP server listening", logger.Operation("Start"), logger.Address(address))

	shutdownSignals := make(chan os.Signal, 1)
	signal.Notify(shutdownSignals, os.Interrupt, syscall.SIGTERM)
	defer signal.Stop(shutdownSignals)

	select {
	case err := <-serveErrs:
		if err != nil && !errors.Is(err, http.ErrServerClosed) {
			logger.Fatal("server", "http server exited unexpectedly", err, logger.Operation("ListenAndServe"), logger.Address(address))
		}
		logger.Info("server", "HTTP server stopped", logger.Operation("ListenAndServe"), logger.Address(address))
	case shutdownSignal := <-shutdownSignals:
		if readiness != nil {
			readiness.MarkNotReady()
		}
		logger.Info("server", "shutdown signal received", logger.Operation("Shutdown"), logger.Address(address), logger.String("signal", shutdownSignal.String()))

		shutdownContext, cancel := context.WithTimeout(context.Background(), 10*time.Second)
		defer cancel()

		if err := server.Shutdown(shutdownContext); err != nil {
			logger.Fatal("server", "graceful shutdown failed", err, logger.Operation("Shutdown"), logger.Address(address))
		}

		if err := <-serveErrs; err != nil && !errors.Is(err, http.ErrServerClosed) {
			logger.Fatal("server", "http server exited unexpectedly during shutdown", err, logger.Operation("ListenAndServe"), logger.Address(address))
		}

		logger.Info("server", "HTTP server shutdown complete", logger.Operation("Shutdown"), logger.Address(address))
	}
}

package security

import (
	"net/http"
)

// SecurityHeaders holds configuration for security headers
type SecurityHeaders struct {
	CSP                string
	XSSProtection      string
	ContentTypeOptions string
	FrameOptions       string
	ReferrerPolicy     string
	PermissionsPolicy  string
}

// DefaultSecurityHeaders returns default security header values
func DefaultSecurityHeaders() SecurityHeaders {
	return SecurityHeaders{
		CSP: "default-src 'self'; " +
			"script-src 'self' 'unsafe-inline'; " +
			"style-src 'self' 'unsafe-inline'; " +
			"img-src 'self' data: https:; " +
			"connect-src 'self'; " +
			"font-src 'self'; " +
			"object-src 'none'; " +
			"media-src 'self'; " +
			"frame-src 'none'; " +
			"worker-src 'none'; " +
			"child-src 'none'; " +
			"form-action 'self'; " +
			"upgrade-insecure-requests",
		XSSProtection:      "1; mode=block",
		ContentTypeOptions: "nosniff",
		FrameOptions:       "DENY",
		ReferrerPolicy:     "strict-origin-when-cross-origin",
		PermissionsPolicy:  "camera=(), microphone=(), geolocation=(), gyroscope=(), magnetometer=(), usb=()",
	}
}

// SecurityHeadersMiddleware creates middleware that adds security headers to responses
func SecurityHeadersMiddleware(headers SecurityHeaders) func(http.Handler) http.Handler {
	return func(next http.Handler) http.Handler {
		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			// Set Content Security Policy
			if headers.CSP != "" {
				w.Header().Set("Content-Security-Policy", headers.CSP)
			}

			// Set XSS Protection
			if headers.XSSProtection != "" {
				w.Header().Set("X-XSS-Protection", headers.XSSProtection)
			}

			// Set Content Type Options
			if headers.ContentTypeOptions != "" {
				w.Header().Set("X-Content-Type-Options", headers.ContentTypeOptions)
			}

			// Set Frame Options
			if headers.FrameOptions != "" {
				w.Header().Set("X-Frame-Options", headers.FrameOptions)
			}

			// Set Referrer Policy
			if headers.ReferrerPolicy != "" {
				w.Header().Set("Referrer-Policy", headers.ReferrerPolicy)
			}

			// Set Permissions Policy
			if headers.PermissionsPolicy != "" {
				w.Header().Set("Permissions-Policy", headers.PermissionsPolicy)
			}

			// Set additional security headers
			w.Header().Set("X-Permitted-Cross-Domain-Policies", "none")
			w.Header().Set("Cross-Origin-Embedder-Policy", "require-corp")
			w.Header().Set("Cross-Origin-Opener-Policy", "same-origin")
			w.Header().Set("Cross-Origin-Resource-Policy", "same-origin")

			// Remove server information
			w.Header().Set("Server", "")

			next.ServeHTTP(w, r)
		})
	}
}

// CreateSecurityHeadersMiddleware creates a security headers middleware with default settings
func CreateSecurityHeadersMiddleware() func(http.Handler) http.Handler {
	return SecurityHeadersMiddleware(DefaultSecurityHeaders())
}

package security

import (
	"net"
	"net/http"
	"os"
	"strings"
	"sync"
	"time"

	"golang.org/x/time/rate"
)

const trustProxyHeadersEnv = "TRUST_PROXY_HEADERS"

// RateLimiter manages rate limiting for different clients/IPs
type RateLimiter struct {
	limiters map[string]*rate.Limiter
	mu       sync.RWMutex
	rate     rate.Limit
	burst    int
	cleanup  time.Duration
}

// NewRateLimiter creates a new rate limiter
func NewRateLimiter(r rate.Limit, b int, cleanup time.Duration) *RateLimiter {
	rl := &RateLimiter{
		limiters: make(map[string]*rate.Limiter),
		rate:     r,
		burst:    b,
		cleanup:  cleanup,
	}

	// Start cleanup goroutine
	go rl.cleanupRoutine()

	return rl
}

// GetLimiter returns the rate limiter for a given key (IP address)
func (rl *RateLimiter) GetLimiter(key string) *rate.Limiter {
	rl.mu.Lock()
	defer rl.mu.Unlock()

	limiter, exists := rl.limiters[key]
	if !exists {
		limiter = rate.NewLimiter(rl.rate, rl.burst)
		rl.limiters[key] = limiter
	}

	return limiter
}

// cleanupRoutine periodically removes unused limiters
func (rl *RateLimiter) cleanupRoutine() {
	ticker := time.NewTicker(rl.cleanup)
	defer ticker.Stop()

	for range ticker.C {
		rl.mu.Lock()
		for key, limiter := range rl.limiters {
			// Remove limiters that haven't been used recently
			if limiter.TokensAt(time.Now()) == float64(rl.burst) {
				delete(rl.limiters, key)
			}
		}
		rl.mu.Unlock()
	}
}

// RateLimitConfig holds configuration for different rate limits
type RateLimitConfig struct {
	LoginRate       rate.Limit // requests per second for login attempts
	LoginBurst      int        // max burst for login attempts
	GeneralRate     rate.Limit // requests per second for general API
	GeneralBurst    int        // max burst for general API
	CleanupInterval time.Duration
}

// DefaultRateLimitConfig returns sensible default rate limits
func DefaultRateLimitConfig() RateLimitConfig {
	return RateLimitConfig{
		LoginRate:       rate.Every(10 * time.Second), // 1 login attempt per 10 seconds
		LoginBurst:      3,                            // Allow burst of 3 attempts
		GeneralRate:     rate.Every(time.Second),      // 1 request per second
		GeneralBurst:    10,                           // Allow burst of 10 requests
		CleanupInterval: 5 * time.Minute,              // Cleanup every 5 minutes
	}
}

// RateLimitMiddleware creates a rate limiting middleware
func RateLimitMiddleware(limiter *RateLimiter) func(http.Handler) http.Handler {
	return func(next http.Handler) http.Handler {
		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			// Get client IP
			ip := getClientIP(r)

			// Check rate limit
			if !limiter.GetLimiter(ip).Allow() {
				WriteRateLimited(w, RuntimeReasonRateLimited)
				return
			}

			next.ServeHTTP(w, r)
		})
	}
}

// LoginRateLimitMiddleware creates a stricter rate limit for login endpoints
func LoginRateLimitMiddleware(limiter *RateLimiter) func(http.Handler) http.Handler {
	return func(next http.Handler) http.Handler {
		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			// Get client IP
			ip := getClientIP(r)

			// Check rate limit
			if !limiter.GetLimiter(ip).Allow() {
				WriteRateLimited(w, RuntimeReasonLoginRateLimited)
				return
			}

			next.ServeHTTP(w, r)
		})
	}
}

// getClientIP extracts the client IP address from the request.
// Forwarded headers are only trusted when the deployment explicitly opts in.
func getClientIP(r *http.Request) string {
	if r == nil {
		return ""
	}

	if trustProxyHeaders() {
		if forwarded := firstForwardedFor(r.Header.Get("X-Forwarded-For")); forwarded != "" {
			return forwarded
		}

		if realIP := headerIP(r.Header.Get("X-Real-IP")); realIP != "" {
			return realIP
		}
	}

	return remoteAddressHost(r.RemoteAddr)
}

func trustProxyHeaders() bool {
	switch strings.ToLower(strings.TrimSpace(os.Getenv(trustProxyHeadersEnv))) {
	case "1", "true", "yes", "on":
		return true
	default:
		return false
	}
}

func firstForwardedFor(value string) string {
	if strings.TrimSpace(value) == "" {
		return ""
	}
	parts := strings.Split(value, ",")
	return headerIP(parts[0])
}

func headerIP(value string) string {
	value = strings.TrimSpace(value)
	if value == "" || net.ParseIP(value) == nil {
		return ""
	}
	return value
}

func remoteAddressHost(remoteAddr string) string {
	remoteAddr = strings.TrimSpace(remoteAddr)
	if remoteAddr == "" {
		return ""
	}
	host, _, err := net.SplitHostPort(remoteAddr)
	if err == nil {
		return host
	}
	return remoteAddr
}

// RateLimitManager manages multiple rate limiters for different endpoints
type RateLimitManager struct {
	loginLimiter   *RateLimiter
	generalLimiter *RateLimiter
}

// NewRateLimitManager creates a new rate limit manager with default configuration
func NewRateLimitManager() *RateLimitManager {
	config := DefaultRateLimitConfig()

	return &RateLimitManager{
		loginLimiter: NewRateLimiter(
			config.LoginRate,
			config.LoginBurst,
			config.CleanupInterval,
		),
		generalLimiter: NewRateLimiter(
			config.GeneralRate,
			config.GeneralBurst,
			config.CleanupInterval,
		),
	}
}

// NewCustomRateLimitManager creates a rate limit manager with custom configuration
func NewCustomRateLimitManager(config RateLimitConfig) *RateLimitManager {
	return &RateLimitManager{
		loginLimiter: NewRateLimiter(
			config.LoginRate,
			config.LoginBurst,
			config.CleanupInterval,
		),
		generalLimiter: NewRateLimiter(
			config.GeneralRate,
			config.GeneralBurst,
			config.CleanupInterval,
		),
	}
}

// GetLoginMiddleware returns the login rate limiting middleware
func (rlm *RateLimitManager) GetLoginMiddleware() func(http.Handler) http.Handler {
	return LoginRateLimitMiddleware(rlm.loginLimiter)
}

// GetGeneralMiddleware returns the general rate limiting middleware
func (rlm *RateLimitManager) GetGeneralMiddleware() func(http.Handler) http.Handler {
	return RateLimitMiddleware(rlm.generalLimiter)
}

package main

import (
	"net/http"

	appenv "socialpredict/internal/app/env"
	appruntime "socialpredict/internal/app/runtime"
	authsvc "socialpredict/internal/service/auth"
	"socialpredict/logger"
	"socialpredict/migration"
	_ "socialpredict/migration/migrations" // <-- side-effect import: registers migrations via init()
	"socialpredict/seed"
	"socialpredict/server"
	"socialpredict/setup"
)

func main() {
	// Secure endpoint example
	http.Handle("/secure", authsvc.Authenticate(http.HandlerFunc(secureEndpoint)))

	readiness := appruntime.NewReadiness()

	// Load local development env overrides from .env.dev when present.
	if err := appenv.LoadDevFile(); err != nil {
		logger.Warn("startup", "development environment override not loaded", logger.Operation("LoadDevFile"), logger.Err(err))
	}

	dbCfg, err := appruntime.LoadDBConfigFromEnv()
	if err != nil {
		logger.Fatal("startup", "database configuration unavailable", err, logger.Operation("LoadDBConfigFromEnv"))
	}

	db, err := appruntime.InitDB(dbCfg, appruntime.PostgresFactory{})
	if err != nil {
		logger.Fatal("startup", "database initialization failed", err, logger.Operation("InitDB"))
	}
	defer func() {
		if err := appruntime.CloseDB(db); err != nil {
			logger.Warn("startup", "database shutdown reported a warning", logger.Operation("CloseDB"), logger.Err(err))
		}
	}()

	const MAX_ATTEMPTS = 20
	if err := seed.EnsureDBReady(db, MAX_ATTEMPTS); err != nil {
		logger.Fatal("startup", "database readiness check failed", err, logger.Operation("EnsureDBReady"))
	}

	configService, err := appruntime.LoadConfigService(setup.EmbeddedSource{})
	if err != nil {
		logger.Fatal("startup", "configuration service initialization failed", err, logger.Operation("LoadConfigService"))
	}

	startupMode, err := appruntime.LoadStartupMutationModeFromEnv()
	if err != nil {
		logger.Fatal("startup", "startup mutation mode unavailable", err, logger.Operation("LoadStartupMutationModeFromEnv"))
	}

	if startupMode.Writer {
		logger.Info("startup", "startup writer enabled for database migrations and seeds", logger.Operation("StartupMutationMode"))
	} else {
		logger.Info("startup", "startup writer disabled; verifying database schema before serving", logger.Operation("StartupMutationMode"))
	}
	if err := runStartupMutations(db, configService, startupMode, startupMutationHooks{
		migrate:      migration.MigrateDB,
		verify:       migration.VerifyApplied,
		seedUsers:    seed.SeedUsers,
		seedHomepage: seed.SeedHomepage,
	}); err != nil {
		logger.Fatal("startup", "startup database mutation check failed", err, logger.Operation("RunStartupMutations"))
	}

	readiness.MarkReady()

	server.Start(openAPISpec, swaggerUIFS, db, configService, readiness)
}

